package main


import (
  "fmt"
  "strings"
  "net/http"
  "io"
)


func main() {


  url := "https://192.168.0.1/proxy/protect/integration/v1/liveviews"
  method := "POST"


  payload := strings.NewReader(`{
  "id": "string",
  "modelKey": "string",
  "name": "string",
  "isDefault": true,
  "isGlobal": true,
  "owner": "string",
  "layout": 0,
  "slots": [
    {
      "cameras": [
        "string"
      ],
      "cycleMode": "motion",
      "cycleInterval": 0
    }
  ]
}`)


  client := &http.Client {
  }
  req, err := http.NewRequest(method, url, payload)


  if err != nil {
    fmt.Println(err)
    return
  }
  req.Header.Add("Accept", "application/json")
  req.Header.Add("X-API-Key", "<X-API-Key>")
  req.Header.Add("Content-Type", "application/json")


  res, err := client.Do(req)
  if err != nil {
    fmt.Println(err)
    return
  }
  defer res.Body.Close()


  body, err := io.ReadAll(res.Body)
  if err != nil {
    fmt.Println(err)
    return
  }
  fmt.Println(string(body))

